import{_ as r,C as s,o as e,c as n,a4 as a,b as d,w as o,a as l,E as c,a5 as h}from"./chunks/framework.Bvl0dEsZ.js";const w=JSON.parse('{"title":"Why Specialist Agent?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/why.md","filePath":"guide/why.md"}'),p={name:"guide/why.md"};function u(g,t,m,f,b,y){const i=s("Mermaid");return e(),n("div",null,[t[1]||(t[1]=a(`<h1 id="why-specialist-agent" tabindex="-1">Why Specialist Agent? <a class="header-anchor" href="#why-specialist-agent" aria-label="Permalink to &quot;Why Specialist Agent?&quot;">​</a></h1><h2 id="the-problem-with-generic-ai-coding" tabindex="-1">The Problem with Generic AI Coding <a class="header-anchor" href="#the-problem-with-generic-ai-coding" aria-label="Permalink to &quot;The Problem with Generic AI Coding&quot;">​</a></h2><h3 id="one-size-fits-all-prompts-fail-at-scale" tabindex="-1">One-size-fits-all prompts fail at scale <a class="header-anchor" href="#one-size-fits-all-prompts-fail-at-scale" aria-label="Permalink to &quot;One-size-fits-all prompts fail at scale&quot;">​</a></h3><p>Generic LLM prompts don&#39;t understand your architecture. They produce inconsistent code across modules, ignore existing patterns, and create technical debt faster than they save time.</p><p>A generic prompt doesn&#39;t know that your project uses a service layer pattern, or that your forms follow a specific validation strategy. It generates &quot;working code&quot; that doesn&#39;t fit your codebase.</p><h3 id="no-verification-means-no-trust" tabindex="-1">No verification means no trust <a class="header-anchor" href="#no-verification-means-no-trust" aria-label="Permalink to &quot;No verification means no trust&quot;">​</a></h3><p>Most AI coding tools claim &quot;done&quot; without proof. No test output, no build verification, no architecture compliance check. You end up reviewing every line anyway, which defeats the purpose.</p><div class="warning custom-block"><p class="custom-block-title">The &quot;Should Work&quot; Problem</p><p>If an AI tool says &quot;the tests should pass&quot; instead of actually running the tests, you can&#39;t trust its output. Every claim needs evidence.</p></div><h3 id="context-pollution-degrades-quality" tabindex="-1">Context pollution degrades quality <a class="header-anchor" href="#context-pollution-degrades-quality" aria-label="Permalink to &quot;Context pollution degrades quality&quot;">​</a></h3><p>Long conversations accumulate stale context. Instructions from earlier messages get lost, naming conventions drift, and later outputs diverge from earlier decisions. By the 10th task, the AI has forgotten what it agreed to in the 1st.</p><h2 id="how-specialist-agent-solves-this" tabindex="-1">How Specialist Agent Solves This <a class="header-anchor" href="#how-specialist-agent-solves-this" aria-label="Permalink to &quot;How Specialist Agent Solves This&quot;">​</a></h2><h3 id="specialized-agents-not-generic-prompts" tabindex="-1">Specialized agents, not generic prompts <a class="header-anchor" href="#specialized-agents-not-generic-prompts" aria-label="Permalink to &quot;Specialized agents, not generic prompts&quot;">​</a></h3><p>27+ agents, each with deep domain expertise:</p><table tabindex="0"><thead><tr><th>Need</th><th>Agent</th><th>Expertise</th></tr></thead><tbody><tr><td>Scaffold a module</td><td><code>@builder</code></td><td>Knows YOUR architecture patterns</td></tr><tr><td>Review a PR</td><td><code>@reviewer</code></td><td>3-in-1: spec, quality, architecture</td></tr><tr><td>Fix a production bug</td><td><code>@debugger</code></td><td>Systematic 4-phase debugging</td></tr><tr><td>Design an API</td><td><code>@api</code></td><td>REST/GraphQL best practices</td></tr><tr><td>Add payments</td><td><code>@finance</code></td><td>Stripe, PCI compliance</td></tr><tr><td>Security audit</td><td><code>@security</code></td><td>OWASP Top 10, JWT, encryption</td></tr></tbody></table><p>Each agent has a focused mission, specific workflow, and clear output format. No &quot;jack of all trades&quot; - domain experts for every task.</p><h3 id="proof-based-verification" tabindex="-1">Proof-based verification <a class="header-anchor" href="#proof-based-verification" aria-label="Permalink to &quot;Proof-based verification&quot;">​</a></h3><p>Every agent must show actual output before claiming completion:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ @builder: Created 6 files, all tests passing (14/14)</span></span>
<span class="line"><span>✅ @reviewer: Found 2 issues - both resolved</span></span>
<span class="line"><span>✅ @tdd: RED (3 failing) → GREEN (3 passing) → REFACTOR (3 passing)</span></span></code></pre></div><p>Anti-rationalization tables prevent shortcuts. If an agent catches itself thinking &quot;just this once&quot; or &quot;it&#39;s obvious&quot; - it stops and follows the process.</p><h3 id="context-isolation-by-design" tabindex="-1">Context isolation by design <a class="header-anchor" href="#context-isolation-by-design" aria-label="Permalink to &quot;Context isolation by design&quot;">​</a></h3><p><code>@orchestrator</code> and <code>@executor</code> use fresh context per subagent. Each task gets a self-contained prompt - no accumulated context pollution:</p>`,21)),(e(),d(h,null,{default:o(()=>[c(i,{id:"mermaid-143",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20A%5BYou%5D%20--%3E%20B%5B%22%40orchestrator%22%5D%0A%20%20%20%20B%20--%3E%20C%5B%22%40builder%20(fresh%20context)%22%5D%0A%20%20%20%20B%20--%3E%20D%5B%22%40reviewer%20(fresh%20context)%22%5D%0A%20%20%20%20B%20--%3E%20E%5B%22%40tester%20(fresh%20context)%22%5D%0A"})]),fallback:o(()=>[...t[0]||(t[0]=[l(" Loading... ",-1)])]),_:1})),t[2]||(t[2]=a('<h3 id="architecture-aware-from-day-one" tabindex="-1">Architecture-aware from day one <a class="header-anchor" href="#architecture-aware-from-day-one" aria-label="Permalink to &quot;Architecture-aware from day one&quot;">​</a></h3><p>Agents read your <code>ARCHITECTURE.md</code> and follow YOUR conventions:</p><ul><li>Your naming patterns, not generic ones</li><li>Your folder structure, not a default template</li><li>Your state management choice, not &quot;whatever&quot;</li><li>Your testing strategy, not skipped tests</li></ul><h2 id="generic-ai-vs-specialist-agent" tabindex="-1">Generic AI vs Specialist Agent <a class="header-anchor" href="#generic-ai-vs-specialist-agent" aria-label="Permalink to &quot;Generic AI vs Specialist Agent&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Aspect</th><th>Generic AI</th><th>Specialist Agent</th></tr></thead><tbody><tr><td>Architecture awareness</td><td>None</td><td>Reads ARCHITECTURE.md</td></tr><tr><td>Code verification</td><td>&quot;Should work&quot;</td><td>Actual test/build output</td></tr><tr><td>Cost control</td><td>Unpredictable</td><td>Adaptive planning + Lite mode</td></tr><tr><td>Agent specialization</td><td>One model does everything</td><td>27+ domain experts</td></tr><tr><td>Governance</td><td>None</td><td>Anti-rationalization + verification</td></tr><tr><td>Framework support</td><td>Generic</td><td>7 tailored packs</td></tr><tr><td>Context management</td><td>Degrades over time</td><td>Fresh context per task</td></tr><tr><td>Review quality</td><td>&quot;LGTM&quot;</td><td>Evidence-based verdicts</td></tr></tbody></table><h2 id="lite-mode-quality-at-a-fraction-of-the-cost" tabindex="-1">Lite Mode: Quality at a Fraction of the Cost <a class="header-anchor" href="#lite-mode-quality-at-a-fraction-of-the-cost" aria-label="Permalink to &quot;Lite Mode: Quality at a Fraction of the Cost&quot;">​</a></h2><p>Every agent has a Lite variant that uses Haiku instead of Sonnet/Opus:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Best For</th><th>Cost</th></tr></thead><tbody><tr><td><strong>Full</strong></td><td>Complex features, architecture decisions, PRs</td><td>Standard</td></tr><tr><td><strong>Lite</strong></td><td>Quick scaffolding, simple components, rapid iteration</td><td><strong>60-80% less</strong></td></tr></tbody></table><p>The <code>/estimate</code> skill tells you the expected cost before you start. No surprises.</p><div class="tip custom-block"><p class="custom-block-title">When to use Lite Mode</p><p>Start with Lite for scaffolding and rapid prototyping. Switch to Full for complex business logic, security-critical code, and final reviews.</p></div><h2 id="what-s-next" tabindex="-1">What&#39;s Next? <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s Next?&quot;">​</a></h2><ul><li><a href="/pr-preview/pr-52/guide/quick-start.html">Quick Start</a> - Get running in 2 minutes</li><li><a href="/pr-preview/pr-52/reference/agents.html">Browse all agents</a> - See what each agent does</li><li><a href="/pr-preview/pr-52/scenarios/">Real-world scenarios</a> - How teams use Specialist Agent daily</li></ul>',12))])}const q=r(p,[["render",u]]);export{w as __pageData,q as default};
